const QUERY_KEYS=Object.freeze(["webappId","webappid","webAppId","appId","appid","workflowId","workflowid","id","code"]),PATH_MARKERS=new Set(["app","apps","workflow","workflows","community","detail","webapp"]);function cleanText(t){return null==t?"":String(t).trim()}function decodeText(t){try{return decodeURIComponent(t)}catch{return t}}function urlLike(t){return/[/?#]/.test(t)||/runninghub\.(?:cn|ai)/i.test(t)}function urlFromText(t){const e=decodeText(t);return/^https?:\/\//i.test(e)?e:/runninghub\.(?:cn|ai)/i.test(e)?`https://${e.replace(/^\/+/,"")}`:""}function idFromSearch(t){const e=[t.searchParams];t.hash&&t.hash.includes("?")&&e.push(new URLSearchParams(t.hash.slice(t.hash.indexOf("?")+1)));for(const t of e)for(const e of QUERY_KEYS){const n=cleanText(t.get(e));if(n)return n}return""}function idFromPath(t){const e=t.pathname.split("/").map(cleanText).filter(Boolean);for(let t=0;t<e.length-1;t++)if(PATH_MARKERS.has(e[t].toLowerCase()))return e[t+1];return e.length?e[e.length-1]:""}export function normalizeRhAppIdHost(t){const e=cleanText(t);if(!e)return"";if(!urlLike(e))return e;const n=urlFromText(e);if(n)try{const t=new URL(n);return idFromSearch(t)||idFromPath(t)||e}catch{}const r=decodeText(e).match(/\d{5,}/);return r?r[0]:e}export function webappIdToCanonicalStringHost(t){if(null==t)return"";if("bigint"==typeof t)return t.toString();const e=normalizeRhAppIdHost(t);if(!e)return"";if(/^\d+$/.test(e))return e;const n=Number(e);return Number.isFinite(n)&&n>0?String(Math.trunc(n)):e}